#include<bits/stdc++.h>
using namespace std;

const int N = 1e5 + 5;
const int M = 500005;
const int INF = 0x3f3f3f3f;

int n, m;
int a[N];
int d[N], f[N]; 
bool vis[N];
vector<int> e1[N];
vector<int> e2[N];

void SPFA1() {
    memset(d, 0x3f, sizeof d);
    queue<int> q;
    q.push(1);
    d[1] = a[1];
    vis[1] = true;
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        vis[u] = false;
        for (int v : e1[u]) {
            int new_val = min(d[u], a[v]);
            if (new_val < d[v]) {
                d[v] = new_val;
                if (!vis[v]) {
                    vis[v] = true;
                    q.push(v);
                }
            }
        }
    }
}

void SPFA2() {
    memset(f, -1, sizeof f);
    memset(vis, 0, sizeof vis);
    queue<int> q;
    q.push(n);
    f[n] = a[n];
    vis[n] = true;
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        vis[u] = false;
        for (int v : e2[u]) {
            int new_val = max(f[u], a[v]);
            if (new_val > f[v]) {
                f[v] = new_val;
                if (!vis[v]) {
                    vis[v] = true;
                    q.push(v);
                }
            }
        }
    }
}

int main() {
    cin.tie(0)->sync_with_stdio(0);
    cin >> n >> m;
    for (int i = 1; i <= n; i++) cin >> a[i];
    for (int i = 1; i <= m; i++) {
        int x, y, z;
        cin >> x >> y >> z;
        if (z == 1) {
            e1[x].push_back(y);
            e2[y].push_back(x);
        } else {
            e1[x].push_back(y);
            e1[y].push_back(x);
            e2[x].push_back(y);
            e2[y].push_back(x);
        }
    }
    SPFA1();
    SPFA2();
    int ans = 0;
    for (int i = 1; i <= n; i++) {
        if (d[i] != INF && f[i] != -1) {
            ans = max(ans, f[i] - d[i]);
        }
    }
    cout << ans;
    return 0;
}
